#include<bits/stdc++.h>
#define ll long long
#define CI const int 
using namespace std;
CI MAXN=2e2+5;
CI dx[]={0,-2,-1,1,2,-2,-1,1,2};
CI dy[]={0,1,2,2,1,-1,-2,-2,-1};
bool MAP[MAXN][MAXN]={false};
ll f[MAXN][MAXN]={0};int n,m,x,y;
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	scanf("%d%d%d%d",&n,&m,&x,&y),f[0][0]=1;
	for(int i=0;i<9;++i)MAP[x+dx[i]][y+dy[i]]=true;
	for(int i=0;i<=n;++i){
		for(int j=0;j<=m;++j){
			if(MAP[i][j]||(!(i+j)))continue;
			f[i][j]=f[i-1][j]+f[i][j-1];
		}
	}printf("%lld",f[n][m]);
	return false;
}
